import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import AdminHeader from './AdminHeader'; // Add this import
import './StandaloneAdminDashboard.css';

const StandaloneAdminDashboard = () => {
  const [admin, setAdmin] = useState(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [users, setUsers] = useState([]);
  const [requests, setRequests] = useState([]);
  const [stats, setStats] = useState({});
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    // Check if admin is logged in
    const adminSession = JSON.parse(sessionStorage.getItem('adminSession'));
    
    if (!adminSession || !adminSession.isAdmin) {
      navigate('/standalone-admin');
      return;
    }
    
    setAdmin(adminSession);
    loadData();
  }, [navigate]);

  const loadData = async () => {
    try {
      setLoading(true);
      
      // Load all data in parallel
      const [statsResponse, usersResponse, requestsResponse] = await Promise.all([
        fetch('http://localhost:5000/api/admin-data/stats').then(res => res.json()),
        fetch('http://localhost:5000/api/admin-data/users').then(res => res.json()),
        fetch('http://localhost:5000/api/admin-data/mentorship-requests').then(res => res.json())
      ]);

      if (statsResponse.success) setStats(statsResponse.stats);
      if (usersResponse.success) setUsers(usersResponse.users);
      if (requestsResponse.success) setRequests(requestsResponse.requests);

    } catch (error) {
      console.error('Error loading data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleUpdateRequest = async (requestId, status) => {
    try {
      const response = await fetch(`http://localhost:5000/api/admin-data/mentorship-requests/${requestId}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ status })
      });

      const data = await response.json();
      
      if (data.success) {
        // Refresh requests
        const requestsResponse = await fetch('http://localhost:5000/api/admin-data/mentorship-requests').then(res => res.json());
        if (requestsResponse.success) setRequests(requestsResponse.requests);
        
        // Refresh stats
        const statsResponse = await fetch('http://localhost:5000/api/admin-data/stats').then(res => res.json());
        if (statsResponse.success) setStats(statsResponse.stats);
        
        alert(`Request ${status} successfully!`);
      }
    } catch (error) {
      console.error('Error updating request:', error);
      alert('Error updating request');
    }
  };

  const getStatusBadge = (status) => {
    const statusConfig = {
      pending: { class: 'status-pending', text: '⏳ Pending' },
      accepted: { class: 'status-accepted', text: '✅ Accepted' },
      rejected: { class: 'status-rejected', text: '❌ Rejected' },
      completed: { class: 'status-completed', text: '🎉 Completed' }
    };
    
    const config = statusConfig[status] || statusConfig.pending;
    return <span className={`status-badge ${config.class}`}>{config.text}</span>;
  };

  if (!admin) {
    return (
      <div className="admin-loading">
        <div className="spinner"></div>
        <p>Checking admin access...</p>
      </div>
    );
  }

  return (
    <div className="standalone-admin-dashboard">
      {/* Use Admin Header instead of regular header */}
      <AdminHeader />
      
      {/* Rest of your admin dashboard content remains the same */}
      <div className="admin-nav">
        <button 
          className={`nav-btn ${activeTab === 'dashboard' ? 'active' : ''}`}
          onClick={() => setActiveTab('dashboard')}
        >
          📊 Dashboard
        </button>
        <button 
          className={`nav-btn ${activeTab === 'users' ? 'active' : ''}`}
          onClick={() => setActiveTab('users')}
        >
          👥 User Management ({users.length})
        </button>
        <button 
          className={`nav-btn ${activeTab === 'requests' ? 'active' : ''}`}
          onClick={() => setActiveTab('requests')}
        >
          📨 Mentorship Requests ({requests.filter(req => req.status === 'pending').length})
        </button>
      </div>

      {/* Dashboard Content */}
      <div className="admin-content">
        {/* ... rest of your dashboard content ... */}
      </div>
    </div>
  );
};

export default StandaloneAdminDashboard;
